import api from "./axios";

// GET /api/sales
export const getSales = () => api.get("/sales");

// GET /api/sales/:id
export const getSaleById = (id) => api.get(`/sales/${id}`);

// POST /api/sales  (backend supports "/" AND "/add")
export const addSale = (data) => api.post("/sales", data);

// PUT /api/sales/:id
export const updateSale = (id, data) => api.put(`/sales/${id}`, data);

// DELETE /api/sales/:id
export const deleteSale = (id) => api.delete(`/sales/${id}`);

// GET /api/sales/stats?year=2026
export const getSalesStats = (year) => api.get(`/sales/stats?year=${year}`);
